INSERT INTO places_fts VALUES ('poi-042', 'Square du Temple - Elie Wiesel', 'parc', 'parc-urbain', '64 Rue de Bretagne', '', 'Ce jardin paysager devant la mairie du 3ème arrondissement (Paris Centre) est le poumon vert du Haut-Marais. Construit sur l''emplacement de l''ancienne forteresse des Templiers (et de la prison de Louis XVI), c''est aujourd''hui un parc paisible avec une mare aux canards, une cascade artificielle et une pelouse libre d''accès. C''est le spot pique-nique chic des habitants du quartier, calme et parfaitement entretenu.');
