INSERT INTO places_fts VALUES ('poi-119', 'Lafayette Anticipations', 'museum', 'fondation d''art', '9 Rue du Plâtre', '', 'Véritable laboratoire de création au cœur du Marais, cette fondation d''entreprise signée Rem Koolhaas est un espace mutant. Grâce à un jeu de planchers mobiles, le bâtiment s''adapte à chaque exposition d''art contemporain, de design ou de mode. Lafayette Anticipations est le lieu où l''on vient découvrir les artistes qui feront demain, dans une atmosphère de curiosité permanente et d''effervescence intellectuelle.');
