Lt0RLuEK8foRmGBLdk45u5B8f-dMmtobDmcERcb66I91g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"La MEP, incontournable pour la photo contemporaine.","specials":{"cuisine":[],"drinks":[]}}', 'La ''MEP'' est le temple de la photo contemporaine à Paris. Située dans l''Hôtel Hénault de Cantobre (1706), elle offre un contraste saisissant entre ses murs classiques et sa programmation visuelle ultra-moderne et internationale. On y découvre les grands maîtres (Newton, Salgado) comme la jeune garde émergente. La bibliothèque est une mine d''or pour les passionnés. C''est un lieu élégant, calme et inspirant, idéalement situé pour commencer une tournée des galeries du Marais.', 'La MEP, incontournable pour la photo contemporaine.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-059', 'Maison Européenne de la Photographie', 'museum', 'musee', '5/7 Rue de Fourcy', '', 'La ''MEP'' est le temple de la photo contemporaine à Paris. Située dans l''Hôtel Hénault de Cantobre (1706), elle offre un contraste saisissant entre ses murs classiques et sa programmation visuelle ultra-moderne et internationale. On y découvre les grands maîtres (Newton, Salgado) comme la jeune garde émergente. La bibliothèque est une mine d''or pour les passionnés. C''est un lieu élégant, calme et inspirant, idéalement situé pour commencer une tournée des galeries du Marais.');
