INSERT INTO places_fts VALUES ('poi-121', 'Pavillon de l''Arsenal', 'museum', 'architecture', '21 Bd Morland', '', 'Le centre d''information sur l''architecture et l''urbanisme de Paris est un lieu fascinant pour comprendre comment la ville s''est construite et comment elle évolue. Sa maquette géante de Paris est un aimant à regards, tout comme ses expositions thématiques sur le logement ou les jardins urbains. Situé dans un ancien arsenal, c''est une étape indispensable pour tout amoureux de Paname et de ses secrets de construction.');
