ichel."}}', 'Niché dans la pittoresque rue Saint-Séverin, le Rim Café est une escale italienne authentique loin des pièges à touristes classiques du quartier. Sa spécialité ? Les pizzas cuites dans un imposant four au feu de bois visible dès l''entrée. L''accueil y est chaleureux, souvent orchestré par une équipe passionnée qui n''hésite pas à recommander les gnocchis à la pistache, devenus cultes parmi les habitués. La petite terrasse permet de profiter de l''animation du Quartier Latin tout en savourant une cuisine généreuse faite maison.', '• Ne passez pas à côté des Gnocchis à la crème de pistache, c''est la pépite absolue de la carte.
INSERT INTO places_fts VALUES ('poi-rim-cafe', 'Rim Café', 'restaurant', 'italien pizza pates saint-michel terrasse fait-maison', '38 Rue Saint-Séverin, 75005 Paris', '', 'Niché dans la pittoresque rue Saint-Séverin, le Rim Café est une escale italienne authentique loin des pièges à touristes classiques du quartier. Sa spécialité ? Les pizzas cuites dans un imposant four au feu de bois visible dès l''entrée. L''accueil y est chaleureux, souvent orchestré par une équipe passionnée qui n''hésite pas à recommander les gnocchis à la pistache, devenus cultes parmi les habitués. La petite terrasse permet de profiter de l''animation du Quartier Latin tout en savourant une cuisine généreuse faite maison.');
INSERT INTO places VALUES ('poi-131', 'Shakespeare and Company Café', 'shakespeare-cafe', 'café', 'cafe-litteraire', 'chill', 48.852617, 2.347218, 5, '37 Rue de la Bûcherie', '#8ccaf7', 'pin', 1, 4.1, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1CzIunaikQ6grege_XJuK7l_Eu6Upu45EXk_uXvlsa3K-74mkakUuZGTT_rQnf8cOJXLwzd8BHEOUvmpjCAiAwdmsUv1cx-UO8Fx0GIe7BfwcjkPwrPaQwCz9UIIa-CVLbb_tErP9z66G15EXrp5LUvY0ywzJTZDmRah7Uo5mHtIc_nlZn9WrF9l3QoEnOqbDrVLuU41IV7NGsra_mJSZg23wwynay2PkSp_C9329z3jAML1ROX1n9bMADao0BIdg3lAIyzThsWmrQh9H4Z5fgH3jy7S5jdiWklpJpvuHQfHn7W2Bg_T6SNOfMNJH9_N5N33SkLL5Vy9AiFVO1qB_-SKgIPZgEd85bfCs1IhgioCqyMjZOuBJTrr98NQ7JfXfigaZGXBL1iFjFAjINK3e1k36hcfbSXs0QlzQPzvOkYipMY0_K6kbz5ZklicR8&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 4.5, 0, '€', NULL, NULL, NULL, 4.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-litteraire"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1CzIunaikQ6grege_XJuK7l_Eu6Upu45EXk_uXvlsa3K-74mkakUuZGTT_rQnf8cOJXLwzd8BHEOUvmpjCAiAwdmsUv1cx-UO8Fx0GIe7BfwcjkPwrPaQwCz9UIIa-CVLbb_tErP9z66G15EXrp5LUvY0ywzJTZDmRah7Uo5mHtIc_nlZn9WrF9l3QoEnOqbDrVLuU41IV7NGsra_mJSZg23wwynay2PkSp_C9329z3jAML1ROX1n9bMADao0BIdg3lAIyzThsWmrQh9H4Z5fgH3jy7S5jdiWklpJpvuHQfHn7W2Bg_T6SNOfMNJH9_N5N33SkLL5Vy9AiFVO1qB_-SKgIPZgEd85bfCs1IhgioCqyMjZOuBJTrr98NQ7JfXfigaZGXBL1iFjFAjINK3e1k36hcfbSXs0QlzQPzvOkYipMY0_K6kbz5ZklicR8&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Adossé à la librairie anglophone la plus célèbre du monde, ce café offre une vue imprenable sur Notre-Dame à travers ses grandes vitres. Entre les pâtisseries anglo-saxonnes (incroyable lemon pie!), les cafés d''exception et les livres qui traînent sur les tables, c''est le refuge parfait pour les amoureux des lettres. On y respire l''héritage de la Beat Generation dans une version moderne, lumineuse et délicieusement gourmande.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-131', 'Shakespeare and Company Café', 'café', 'cafe-litteraire', '37 Rue de la Bûcherie', '', 'Adossé à la librairie anglophone la plus célèbre du monde, ce café offre une vue imprenable sur Notre-Dame à travers ses grandes vitres. Entre les pâtisseries anglo-saxonnes (incroyable lemon pie!), les cafés d''exception et les livres qui traînent sur les tables, c''est le refuge parfait pour les amoureux des lettres. On y respire l''héritage de la Beat Generation dans une version moderne, lumineuse et délicieusement gourmande.');
INSERT INTO places VALUES ('poi-172', 'Café de la Mairie', 'cafe-mairie-6', 'café', 'cafe-terrasse', 'chill', 48.851508, 2.333704, 6, '8 Pl. Saint-Sulpice', '#8ccaf7', 'pin', 1, 3.2, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2JDuek-ln89-E_SUGymbhUaPdkWSLRqVw8LWGd5TKnqoRaQBrI9XPhZ3NTqRTLN4u8Uo_B51ULmppc7RdP2pMGaR8gEmh0xDljfMe9w2RWzT6ZGUdchdlbhN_u0E-JBbVqv7wfaT3tMjKUyuppUXteNZ4R_k6jKK_9bD098gI9sIESWQA8dM6YSfj549xLg-fj4ruK47Tnx80eld8qV6noYug6tzTwzfo5Q3ae3ERmtZiMWEzQs6TmxE-JDmlLMMGc0K2SdhnNfc_EM0P0VdYcrEZAWVkGirHmO_5hljAp6w&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3, 0, '€', NULL, NULL, NULL, 3, 14, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-terrasse"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3,"dish_price":14,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2JDuek-ln89-E_SUGymbhUaPdkWSLRqVw8LWGd5TKnqoRaQBrI9XPhZ3NTqRTLN4u8Uo_B51ULmppc7RdP2pMGaR8gEmh0xDljfMe9w2RWzT6ZGUdchdlbhN_u0E-JBbVqv7wfaT3tMjKUyuppUXteNZ4R_k6jKK_9bD098gI9sIESWQA8dM6YSfj549xLg-fj4ruK47Tnx80eld8qV6noYug6tzTwzfo5Q3ae3ERmtZiMWEzQs6TmxE-JDmlLMMGc0K2SdhnNfc_EM0P0VdYcrEZAWVkGirHmO_5hljAp6w&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Le Café de la Mairie est l''un des secrets les mieux gardés du 6e arrondissement. Face à l''église Saint-Sulpice, sa terrasse ombragée est un havre de calme absolu. Ici, le café est servi à l''ancienne et le service est d''une politesse rare. On y vient pour lire le journal, discuter à voix basse ou simplement observer la lumière sur la pierre de l''église. C''est le Paris éternel, celui des écrivains et des penseurs, qui s''offre ici en toute simplicité.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-172', 'Café de la Mairie', 'café', 'cafe-terrasse', '8 Pl. Saint-Sulpice', '', 'Le Café de la Mairie est l''un des secrets les mieux gardés du 6e arrondissement. Face à l''église Saint-Sulpice, sa terrasse ombragée est un havre de calme absolu. Ici, le café est servi à l''ancienne et le service est d''une politesse rare. On y vient pour lire le journal, discuter à voix basse ou simplement observer la lumière sur la pierre de l''église. C''est le Paris éternel, celui des écrivains et des penseurs, qui s''offre ici en toute simplicité.');
