INSERT INTO places_fts VALUES ('poi-182', 'L''Eclaireur Boissy d''Anglas', 'museum', 'concept-store', '10 Rue Boissy d''Anglas', '', 'Plus qu une boutique, L’Eclaireur Boissy d’Anglas est un labyrinthe de design et de mode avant-gardiste. Pensé comme un cabinet de curiosités du futur, le lieu expose des pièces de créateurs (Fornasetti, Rick Owens, Ann Demeulemeester) au milieu d''une scénographie mouvante faite d écrans et de miroirs. Un lieu de pélérinage pour les amoureux de l''objet rare et de la création visuelle la plus pointue, où l''on déambule comme dans un musée de l''esthétique contemporaine.');
