INSERT INTO places VALUES ('poi-017', 'Le Carmen', 'le-carmen', 'club', 'club-mansion', 'festif', 48.882085, 2.334219, 9, '34 Rue Duperré', '#ffab60', 'pin', 1, 2.6, 0, '/images/le-carmen.jpg', NULL, 0, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","club-mansion"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/le-carmen.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Ancienne maison close de Bizet. Le décor rococo est fou.","specials":{"cuisine":[],"drinks":[]}}', 'Danser dans l''ancien hôtel particulier de Georges Bizet (là où il aurait composé Carmen !), c''est possible. Un décor rococo délirant : colonnes corinthiennes, fresques au plafond, statues de femmes drapées, cage dorée géante... Le lieu est magnifique le jour comme la nuit. On y boit des cocktails au gin (leur spécialité) et on y danse tard dans la nuit dans une ambiance décadente et romantique. C''est Pigalle version grand siècle.', 'Ancienne maison close de Bizet. Le décor rococo est fou.', 'Pigalle', '[2,12]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-017', 'Le Carmen', 'club', 'club-mansion', '34 Rue Duperré', '', 'Danser dans l''ancien hôtel particulier de Georges Bizet (là où il aurait composé Carmen !), c''est possible. Un décor rococo délirant : colonnes corinthiennes, fresques au plafond, statues de femmes drapées, cage dorée géante... Le lieu est magnifique le jour comme la nuit. On y boit des cocktails au gin (leur spécialité) et on y danse tard dans la nuit dans une ambiance décadente et romantique. C''est Pigalle version grand siècle.');
