INSERT INTO places_fts VALUES ('poi-016', 'Badaboum', 'club', 'club-concert cocktail-bar house-techno disco', '2 bis Rue des Taillandiers', '', 'Temple de la nuit Bastillaise, le Badaboum réussit le pari de concilier une salle de concert pointue, un club électronique de référence et un bar à cocktails sophistiqué. Son ''Appartement'' caché à l''étage offre une parenthèse feutrée et intimiste au-dessus du tumulte de la piste de danse. C''est le lieu parfait pour découvrir les futurs talents de la scène indie avant de finir la nuit sur des rythmes house ou disco.');
