INSERT INTO places_fts VALUES ('poi-clamato', 'Clamato', 'restaurant', 'poisson bistronomie sans reservation restaurant', '80 Rue de Charonne', '', 'Le petite frère marin du Septime (situé juste à côté). Le Clamato, inspiré des oyster bars de la côte est américaine, propose une carte exclusivement iodée hyper fraîche, conçue sous forme de petites assiettes à partager dans une ambiance enfiévrée.');
