PxRMH4buEGha_MVkuU8torvc1KWP4VJeK3aDCtDGkRLsmdaTPTTBR00DVN9aHBBJLeNFDuxRsPU0yGwjr82JhTYERAofIMgjr8iy-3m3Vw1sgGg5OxIuvfldZxXVwEtZmPobJrhhPU_PdWxW3luYCBgY3CZaQ0BIXDDMKHTMKvR2wip3H64l2y3kwN0qWr5XkZRMYo2Rrup-esRamua9BRxBe6zGKo8OfYCI433UhSmEBppfad0US_YdgTgy1EooLfrP-Wvo8HRV5Z8WIP_qS4rAQ92HWoqVivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Une institution discrète parfaite pour un très bon date avec l''Italie dans l''assiette.\n• Réservez au moins deux semaines à l''avance, la salle complète à chaque service.\n• Ne partez pas sans tester le Cannolo sicilien ultra croustillant.","specials":{"cuisine":["Mezzi paccheri langoustines","Cannolo Sicilien","Vitello Tonnato"],"drinks":["Barolo","Vins naturels italiens"],"must_eat":"La précision est la de mise. Les pâtes sont al dente et baignent dans des justes parfaits, à l''image des Mezzi paccheri aux langoustines crues. Du brutal chic.","must_drink":"Magnifique cave italienne, beaucoup de belles quilles nord-italiennes."},"expert_catchline":"Trattoria bourgeoise de très haute volée, pour manger les meilleures pâtes de Paris dans le calme absolu."}', 'Derrière sa devanture boisée, l''Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.', '• Une institution discrète parfaite pour un très bon date avec l''Italie dans l''assiette.
INSERT INTO places_fts VALUES ('poi-osteria-ferrara', 'Osteria Ferrara', 'restaurant', 'italien pâtes convivial bistronomique', '7 Rue du Dahomey', '', 'Derrière sa devanture boisée, l''Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.');
