Bw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXXxeOiQGckHjpECS3rp-ntEIu4dCyb70WOy3AollQMSw--8n5afRg3BYNi8G2cvpNZsHBC4fxTkXiQhoD0BbWPhso26eadvaPFd3QL2WLavLRWAF8oAjMOlv8L_ZUNHcjDUDN0fA7kO1n-zKljNnzAxEyIY-yRGksc4aQew6Dp9ccEjI3l9-Rlf6bw5UcvLnHc0naMDHkn4EklVbc5KXJX3H4beFoUVjvFJfAvTlU6-_jhiw0FCxrvDYZdQhC9b79kYHmi99Mmo27t6VGtsmbwugcT5iGJ46p0BUkVRkXJAQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]}', '["https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfV1NNqcIukw5ylzYPN6uAO7tNOVt2JDv8uMPNjqqDmE673gQgOkskyHRKIIcs0gUp8NdOlV9kw6NNZySy5bdiwdoKGUJlyryRSmCdGO7MrnpTPfVBZVIMJDk0QaQAnLRvhKpttdRJlswcnliMSsxoskdx1yTJgrgLzsQJJGqeSgk49bmG_MrrMKyb0VKb2NnUM0hQgCoVYMY_s8WMqtSMlL3WQyjnmnwNF8WxKCkp98Peddb6TO8KLdswD4LHWMz390CsMZLXlqOrnD7fjk_4KwPGN4plf9DAtlueBikORwBw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXXxeOiQGckHjpECS3rp-ntEIu4dCyb70WOy3AollQMSw--8n5afRg3BYNi8G2cvpNZsHBC4fxTkXiQhoD0BbWPhso26eadvaPFd3QL2WLavLRWAF8oAjMOlv8L_ZUNHcjDUDN0fA7kO1n-zKljNnzAxEyIY-yRGksc4aQew6Dp9ccEjI3l9-Rlf6bw5UcvLnHc0naMDHkn4EklVbc5KXJX3H4beFoUVjvFJfAvTlU6-_jhiw0FCxrvDYZdQhC9b79kYHmi99Mmo27t6VGtsmbwugcT5iGJ46p0BUkVRkXJAQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Pas de réservation le soir : venez tôt (dès 19h) pour avoir une place au comptoir ou une table dans le passage.\n• Commandez 3 à 4 tapas par personne pour un repas complet — les portions sont généreuses.\n• Le poulpe à la plancha (14€) et le tartare de thon (14€) sont les valeurs sûres.\n• Si vous êtes un groupe, demandez la côte de boeuf au kg (80€) qui est servie certains soirs seulement — un coup de fil en avance est conseillé.\n• Les verres de vin nature démarrent à 6€, un prix d''appel rare pour cette qualité dans le quartier.","specials":{"cuisine":["Poulpe à la plancha","Tartare de thon","Épaule d''agneau","Tapas du marché créatives"],"drinks":["250 vins d''auteurs natures","Verres dès 6€","Sélection bio et biodynamique"],"must_eat":"Les tapas changent chaque soir selon le marché. Les classiques qui reviennent souvent : le poulpe à la plancha (14€), le carpaccio de rouget au chou-rave (13€), et le parfait de foie de volaille (10€). En groupe, la côte de boeuf au kilo (80€) est un must.","must_drink":"La cave de 250 références natures est le nerf de guerre. Les verres du soir démarrent à 6€ — un rapport qualité-prix honnête et rare dans le 11ème."},"expert_catchline":"Le QG nocturne du vin nature et des tapas du marché dans un passage secret du 11ème."}', 'Au Passage est le bar à vins et tapas culte du 11ème arrondissement, niché dans un passage piéton intime près de Saint-Sébastien. Le principe est simple : on commande des petites assiettes (tapas du marché ultra-créatives), on partage, et Jessica gère une cave de 250 vins d''auteurs natures et bio. L''ambiance est électrique le soir avec une clientèle de connaisseurs et de foodistas.', '• Pas de réservation le soir : venez tôt (dès 19h) pour avoir une place au comptoir ou une table dans le passage.
INSERT INTO places_fts VALUES ('poi-au-passage', 'Au Passage', 'restaurant', 'bar à vins tapas bistronomique vins natures restaurant', '1 bis Passage Saint-Sébastien', '', 'Au Passage est le bar à vins et tapas culte du 11ème arrondissement, niché dans un passage piéton intime près de Saint-Sébastien. Le principe est simple : on commande des petites assiettes (tapas du marché ultra-créatives), on partage, et Jessica gère une cave de 250 vins d''auteurs natures et bio. L''ambiance est électrique le soir avec une clientèle de connaisseurs et de foodistas.');
INSERT INTO places VALUES ('poi-022', 'Atelier des Lumières', 'atelier-lumieres', 'museum', 'espace-culturel', 'culturel', 48.861615, 2.380813, 11, '38 Rue Saint-Maur', '#c499ff', 'pin', 1, 4.5, 0, '/images/atelier-lumieres.jpg', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":7.5,"festif":4,"culturel":24.5}', '{}', '["museum","espace-culturel"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":17,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/atelier-lumieres.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Expérience immersive sonore et visuelle. Réservez impérativement en ligne.","specials":{"cuisine":[],"drinks":[]}}', 'La première ''imprimerie numérique'' géante de Paris. Dans cette ancienne fonderie du XIXe siècle, les œuvres de Klimt, Van Gogh ou Dalí sont projetées en format XXL sur les murs de 10 mètres de haut et sur le sol, accompagnées d''une musique immersive. Ce n''est pas une exposition, c''est une plongée physique dans la peinture. On marche littéralement dans la couleur. C''est l''expérience artistique idéale pour ceux qui trouvent les musées classiques trop statiques.', 'Expérience immersive sonore et visuelle. Réservez impérativement en ligne.', 'Voltaire', '[9]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-022', 'Atelier des Lumières', 'museum', 'espace-culturel', '38 Rue Saint-Maur', '', 'La première ''imprimerie numérique'' géante de Paris. Dans cette ancienne fonderie du XIXe siècle, les œuvres de Klimt, Van Gogh ou Dalí sont projetées en format XXL sur les murs de 10 mètres de haut et sur le sol, accompagnées d''une musique immersive. Ce n''est pas une exposition, c''est une plongée physique dans la peinture. On marche littéralement dans la couleur. C''est l''expérience artistique idéale pour ceux qui trouvent les musées classiques trop statiques.');
