INSERT INTO places_fts VALUES ('poi-confluence', 'Confluence', 'restaurant', 'bistronomie fusion franco-asiatique gastronomique', '79 Rue de Charonne', '', 'Une prouesse de fusion par le chef Hung Luan Nguyen. Confluence mêle la finesse de la gastronomie française aux saveurs vibrantes de l''Asie (Vietnam, Thaïlande). Le dressage est aussi précis que les goûts sont justes.');
