INSERT INTO places_fts VALUES ('poi-kai-izakaya', 'Kai Izakaya', 'restaurant', 'asian tapas brunch izakaya matcha', '13 Rue Louis Bonnet', '', 'Kai Izakaya est une adresse hybride et décontractée où le Japon rencontre des saveurs street-food mondiales. Connue pour ses Udon créatives (dont une version carbonara mémorable) et ses desserts fusion comme le Croffle au Matcha, c''est le spot parfait pour un brunch asiatique ou un dîner de tapas à partager.');
