INSERT INTO places_fts VALUES ('poi-magma', 'Magma', 'restaurant', 'bistronomie franco-japonais gastronomique seasonal', '9 Rue Jean-Pierre Timbaud', '', 'Le chef Ryuya Ono livre une partition d''une justesse rare. Magma est un laboratoire où la technique française s''efface devant la pureté japonaise du produit. Une cuisine anti-gaspi, agile et émouvante, servie dans un cadre intimiste.');
