INSERT INTO places_fts VALUES ('poi-track-119', 'Track 119 (Deb''s Street Food)', 'restaurant', 'indian pakistani street-food food-court', '119 Rue du Chemin Vert', '', 'Niché dans le hub artistique de Track 119, Deb''s Street Food est une explosion de saveurs indo-pakistanaises. Le lieu respire la culture, mêlant street-art, musique et gastronomie sans complexes. Le clou du spectacle ? Des naans revisités avec des fromages français comme le camembert.');
