INSERT INTO places VALUES ('poi-ama', 'Ama', 'ama', 'restaurant', 'tibetan, asian, momos, authentic', 'chill', 48.8695859, 2.3693877, 11, '28 Rue de la Fontaine au Roi', '#8ccaf7', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXW_a9vHMH8fuWg1i-Tb_Zq_xM_b538cHgDR3P0QaMzsASIOAQ6t7GL3VPGprU6Uzv0TBxHAkmbkypyaAe7K7i6SuxHdtfnxh_0xjTRFllSGXTJzaRUeSuJCdDq_zEXdYXz2G235yZ8gUpxkdkChR_EGwgTibqy-p1nLvbT8s5kgGxE9ncB5Uwf2fHqzboWjkURIyHmeqepPNSH3AAC18FZUAD1KFyccbyYsk249p4ehVVrzvkHoW1J8fmYmJw4nEfR3UFWSXaccjp88mmrzP_32hhJs1eo6OEIYqnYaFMM_Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 16, 0, '€', 6, NULL, NULL, 2.5, 16, 50, '{"chill":100,"festif":20,"culturel":80}', '{}', '["restaurant","tibetan","asian","momos","authentic"]', '{"standard":"Mar-Dim: 12:00–14:30, 19:00–22:30; Fermé Lun","display":"Mar-Dim: 12:00–14:30, 19:00–22:30; Fermé Lun"}', '{"opening_hours_raw":"Mar-Dim: 12:00–14:30, 19:00–22:30; Fermé Lun","reservation_policy":"resa_conseillee","terrace":false,"accessibility":false,"wifi":false,"main_action":{"type":"site","url":"https://www.ama-restaurant.com","label":"SITE WEB"},"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":6,"wine_glass":0,"coffee_price":2.5,"dish_price":16,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Les Momos (Raviolis Tibétains)","items":[{"name":"Momos Boeuf (x8)","price":"11.00€","description":"Vapeur ou grillés, avec sauce piquante maison."},{"name":"Momos Poulet (x8)","price":"11.00€"},{"name":"Momos Légumes (x8)","price":"10.00€"},{"name":"Momos Fromage & Epinards (x8)","price":"12.00€"}]},{"category":"Plats Signatures","items":[{"name":"Shaptra","price":"16.00€","description":"Boeuf sauté au gingembre et piments, servi avec du pain tibétain."},{"name":"Thenthuk","price":"14.50€","description":"Soupe de nouilles tirées à la main, légumes et viande."},{"name":"Gyathuk","price":"15.00€","description":"Nouilles sautées à la tibétaine."}]},{"category":"Accompagnements","items":[{"name":"Tingmo (Pain vapeur)","price":"3.50€"},{"name":"Salade Tibétaine","price":"6.00€"}]},{"category":"Desserts & Thés","items":[{"name":"Tsampa au miel","price":"7.00€"},{"name":"Thé Tibétain (au beurre salé)","price":"4.50€"},{"name":"Lassi Maison","price":"5.50€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXW_a9vHMH8fuWg1i-Tb_Zq_xM_b538cHgDR3P0QaMzsASIOAQ6t7GL3VPGprU6Uzv0TBxHAkmbkypyaAe7K7i6SuxHdtfnxh_0xjTRFllSGXTJzaRUeSuJCdDq_zEXdYXz2G235yZ8gUpxkdkChR_EGwgTibqy-p1nLvbT8s5kgGxE9ncB5Uwf2fHqzboWjkURIyHmeqepPNSH3AAC18FZUAD1KFyccbyYsk249p4ehVVrzvkHoW1J8fmYmJw4nEfR3UFWSXaccjp88mmrzP_32hhJs1eo6OEIYqnYaFMM_Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Ne partez pas sans goûter le thé au beurre salé (Po Cha), c''est une expérience clivante mais incontournable pour comprendre la culture tibétaine.","specials":{"cuisine":["Tibetan Momos","Hand-pulled Noodles","Tingmo Bread"],"drinks":["Tibetan Butter Tea","Homemade Lassi"],"must_eat":"Les Momos Boeuf grillés.","must_drink":"Le thé au beurre salé pour les aventuriers."},"expert_catchline":"La poésie des momos tibétains et de la cuisine d''altitude."}', 'Une immersion authentique au Tibet au coeur du 11ème. Ama (qui signifie ''mère'' en tibétain) propose une cuisine familiale et généreuse. Leurs momos, ces célèbres raviolis farcis, sont préparés chaque jour avec amour et servis avec une sauce piquante dont ils ont le secret. L''ambiance y est calme et spirituelle, parfaite pour une parenthèse loin du tumulte parisien.', 'Ne partez pas sans goûter le thé au beurre salé (Po Cha), c''est une expérience clivante mais incontournable pour comprendre la culture tibétaine.', 'Bonsergent / Goncourt', '[5,11]', '[]', 'ChIJy2v_U6Vz5kcR_p_uE-Ff2-Q');
INSERT INTO places_fts VALUES ('poi-ama', 'Ama', 'restaurant', 'tibetan asian momos authentic', '28 Rue de la Fontaine au Roi', '', 'Une immersion authentique au Tibet au coeur du 11ème. Ama (qui signifie ''mère'' en tibétain) propose une cuisine familiale et généreuse. Leurs momos, ces célèbres raviolis farcis, sont préparés chaque jour avec amour et servis avec une sauce piquante dont ils ont le secret. L''ambiance y est calme et spirituelle, parfaite pour une parenthèse loin du tumulte parisien.');
