INSERT INTO places VALUES ('poi-tarantula', 'Tarántula', 'tarantula', 'restaurant', 'mexican, cantina, modern, natural-wine', 'festif', 48.8553057, 2.375595, 11, '13 bis Rue Keller', '#ffab60', 'pin', 1, 4.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 24, 0, '€', NULL, NULL, 7, 3.5, 24, 50, '{"chill":60,"festif":70,"culturel":40}', '{}', '["restaurant","mexican","cantina","modern","natural-wine"]', '{"standard":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim","display":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim"}', '{"opening_hours_raw":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"https://www.instagram.com/tarantulaparis/","label":"INSTAGRAM"},"happy_hour":null}', '{"avg_budget":55,"is_free":false,"pint_price":0,"wine_glass":7,"coffee_price":3.5,"dish_price":24,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Antojitos (Petites Assiettes)","items":[{"name":"Tacos de champignons sauvages ''hallucinogènes''","price":"12.00€"},{"name":"Oignon Roscoff rôti au piment jaune","price":"14.00€"},{"name":"Tuna Crudo, sauce chilaca","price":"18.00€"},{"name":"Empanada croustillante de Chicharrón","price":"11.00€"}]},{"category":"Platos Fuertes (Plats à partager)","items":[{"name":"Demi-poulet rôti au beurre de piment japone","price":"28.00€"},{"name":"Entrecôte (500g) sauce Café de Paris Mexicana","price":"52.00€","description":"Idéal pour deux."},{"name":"Tacos Cantinero (boeuf braisé lentement)","price":"24.00€"},{"name":"Lieu jaune, salsa verde & herbes fraîches","price":"26.00€"}]},{"category":"Postres (Desserts)","items":[{"name":"Flan au caramel, huile d''olive & romarin frit","price":"10.00€","description":"Le dessert signature incontournable."},{"name":"Gâteau de maïs, crème de Mezcal","price":"9.50€"}]},{"category":"Bebidas","items":[{"name":"Margarita Maison","price":"13.00€"},{"name":"Verre de Mezcal sélection","price":"9.00€"},{"name":"Soda UMÀ Green Tea / Lemonade","price":"7.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Leur flan à l''huile d''olive et au romarin frit est devenu culte en quelques mois : ne terminez pas sans lui. Pour les amateurs de sensations fortes, demandez leur sélection de mezcals artisanaux.","specials":{"cuisine":["Modern Mexican (Norestense)","Cuisine de partage","Vins natures"],"drinks":["Mezcals de petits producteurs","Margaritas d''exception"],"must_eat":"Les Tacos de champignons sauvages et le Flan huile d''olive/romarin.","must_drink":"Une Margarita classique ou un verre de skin-contact wine."},"expert_catchline":"La cantina mexicaine 2.0 : saveurs explosives, ambiance tamisée et vins natures."}', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c''est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.', 'Leur flan à l''huile d''olive et au romarin frit est devenu culte en quelques mois : ne terminez pas sans lui. Pour les amateurs de sensations fortes, demandez leur sélection de mezcals artisanaux.', 'Voltaire', '[9]', '[]', 'ChIJN4EGozVz5kcRcL9OSHhiPWE');
INSERT INTO places_fts VALUES ('poi-tarantula', 'Tarántula', 'restaurant', 'mexican cantina modern natural-wine', '13 bis Rue Keller', '', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c''est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.');
