INSERT INTO places VALUES ('poi-le-dauphin', 'Le Dauphin', 'le-dauphin', 'restaurant', 'tapas, wine-bar, french-sharing, design-icon', 'culturel', 48.871, 2.3698, 11, '131 Avenue Parmentier', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 18, 0, '€', NULL, NULL, 9.5, 3.5, 18, 50, '{"chill":50,"festif":60,"culturel":70}', '{}', '["restaurant","tapas","wine-bar","french-sharing","design-icon"]', '{"standard":"Mar-Ven: 12:00–14:00, 19:00–23:00; Sam: 19:00–23:00; Fermé Dim-Lun","display":"Mar-Ven: 12:00–14:00, 19:00–23:00; Sam: 19:00–23:00; Fermé Dim-Lun"}', '{"opening_hours_raw":"Mar-Ven: 12:00–14:00, 19:00–23:00; Sam: 19:00–23:00; Fermé Dim-Lun","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"https://www.instagram.com/ledauphinparis/","label":"INSTAGRAM"},"happy_hour":null}', '{"avg_budget":60,"is_free":false,"pint_price":0,"wine_glass":9.5,"coffee_price":3.5,"dish_price":18,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Tapassiettes (Sélection du Chef)","items":[{"name":"Sashimi de bonite, sauce soja fumée","price":"18.00€"},{"name":"Croquettes de jambon ibérique","price":"14.00€"},{"name":"Tartare de thon & radis","price":"19.00€"},{"name":"Poulpe grillé, purée de pois chiches","price":"22.00€"},{"name":"Carpaccio de bœuf au parmesan","price":"17.00€"},{"name":"Joue de bœuf braisée au vin rouge","price":"24.00€"},{"name":"Asperges vertes grillées, sabayon agrumes","price":"15.00€"},{"name":"Tartine de moelle, herbes fraîches","price":"12.00€"}]},{"category":"Douceurs","items":[{"name":"Ganache chocolat & huile d''olive","price":"9.00€"},{"name":"Panna cotta aux agrumes","price":"8.50€"},{"name":"Glace maison au lait d''amande","price":"7.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Même s''il y a des tables, manger au grand bar central en marbre est l''expérience ultime ici. Laissez le sommelier choisir vos vins natures, leur cave est l''une des plus pointues de Paris.","specials":{"cuisine":["Modern French Tapas","Wine Bar","High Design"],"drinks":["Vins naturels rares","Sélection pointue du Chateaubriand"],"must_eat":"Les croquettes de jambon ibérique et les sashimis de saison.","must_drink":"Un vin nature blanc de Loire ou du Jura."},"expert_catchline":"Le design rencontre la haute gastronomie en format partage."}', 'Le Dauphin est le petit frère surdoué du Chateaubriand. Dans un décor spectaculaire tout de marbre vêtu, conçu par l''architecte Rem Koolhaas, on y déguste le concept de ''Tapassiettes''. Ici, la haute cuisine se décline en petites portions à partager, avec une sélection de produits d''une qualité folle. C''est à la fois un bar à vin exigeant et une table de design où le chic parisien rencontre l''excellence culinaire.', 'Même s''il y a des tables, manger au grand bar central en marbre est l''expérience ultime ici. Laissez le sommelier choisir vos vins natures, leur cave est l''une des plus pointues de Paris.', 'Goncourt', '[11]', '[]', 'ChIJW0-v__tt5kcRrW0-v__tt5k');
INSERT INTO places_fts VALUES ('poi-le-dauphin', 'Le Dauphin', 'restaurant', 'tapas wine-bar french-sharing design-icon', '131 Avenue Parmentier', '', 'Le Dauphin est le petit frère surdoué du Chateaubriand. Dans un décor spectaculaire tout de marbre vêtu, conçu par l''architecte Rem Koolhaas, on y déguste le concept de ''Tapassiettes''. Ici, la haute cuisine se décline en petites portions à partager, avec une sélection de produits d''une qualité folle. C''est à la fois un bar à vin exigeant et une table de design où le chic parisien rencontre l''excellence culinaire.');
