cials":{"cuisine":["American Burger frites maison (15€)","Côte de bœuf béarnaise (19,50€)","Filet de cabillaud rôti (15€)","Assiette de tapas (10€)","Mi-cuit chocolat (6,50€)","Tarte Tatin (6,50€)"],"drinks":["Pinte (7€ / 5€ en HH)","Vin blanc/rosé (3€ en HH)","Cocktails"],"must_eat":"Le burger maison frites à 15€ ou la côte de bœuf sauce béarnaise à 19,50€. En dessert, le mi-cuit chocolat tendre à cœur à 6,50€ — un classique indétrônable.","expert_catchline":"Happy Hour de 9 heures (15h-00h), terrasse couverte, cuisine maison et l''addition qui reste douce — le QG afterwork du boulevard de la Bastille."}}', 'Grande brasserie posée sur le boulevard de la Bastille, Les Associés joue la carte de la brasserie parisienne classique avec un twist afterwork. Deux terrasses (dont une couverte toute l''année), un intérieur spacieux, une cuisine française maison et un Happy Hour XXL qui s''étire de 15h jusqu''à minuit — le genre d''endroit où tu poses ton sac à la sortie du bureau et tu ne bouges plus de la soirée. La carte mélange burgers, tapas, plats de brasserie et un beau choix de desserts maison.', 'Le Happy Hour va jusqu''à MINUIT — c''est l''un des plus longs du quartier Bastille. Pinte à 5€ et verre de vin à 3€ pendant 9 heures d''affilée. La terrasse couverte est un game-changer quand il pleut. Attention : un avis MisterGoodBeer signale que les prix HH ne seraient pas toujours appliqués — vérifie à l''arrivée.', 'Bastille', '[1,5,8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-309', 'Les Associés', 'restaurant', 'brasserie bar afterwork', '50 Boulevard de la Bastille', '', 'Grande brasserie posée sur le boulevard de la Bastille, Les Associés joue la carte de la brasserie parisienne classique avec un twist afterwork. Deux terrasses (dont une couverte toute l''année), un intérieur spacieux, une cuisine française maison et un Happy Hour XXL qui s''étire de 15h jusqu''à minuit — le genre d''endroit où tu poses ton sac à la sortie du bureau et tu ne bouges plus de la soirée. La carte mélange burgers, tapas, plats de brasserie et un beau choix de desserts maison.');
INSERT INTO places VALUES ('poi-023', 'Supersonic', 'supersonic', 'club', 'salle-concert', 'festif', 48.850313, 2.369708, 12, '9 Rue Biscornet', '#ffab60', 'pin', 1, 4.3, 0, '/images/supersonic.jpg', NULL, 0, 0, '€', 8.5, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","salle-concert"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":8.5,"is_free":false,"pint_price":8.5,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/supersonic.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Concerts et soirées tribute Gratuits avant minuit. Ambiance Rock.","specials":{"cuisine":[],"drinks":[]}}', 'Le sauveur des nuits rock à Paris. Situé près de Bastille, ce club aux allures de loft new-yorkais (balcon intérieur, scène basse) propose des concerts gratuits presque tous les soirs ! Indie rock, post-punk, pop psychédélique... la programmation est pointue et curieuse. Après les concerts, le lieu se transforme en club avec des soirées à thème (''Fuck Forever'' indie pop, ''Sunday Tribute''). C''est toujours plein, ça transpire, c''est vivant et accessible à tous.', 'Concerts et soirées tribute Gratuits avant minuit. Ambiance Rock.', 'Bastille', '[1,5,8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-023', 'Supersonic', 'club', 'salle-concert', '9 Rue Biscornet', '', 'Le sauveur des nuits rock à Paris. Situé près de Bastille, ce club aux allures de loft new-yorkais (balcon intérieur, scène basse) propose des concerts gratuits presque tous les soirs ! Indie rock, post-punk, pop psychédélique... la programmation est pointue et curieuse. Après les concerts, le lieu se transforme en club avec des soirées à thème (''Fuck Forever'' indie pop, ''Sunday Tribute''). C''est toujours plein, ça transpire, c''est vivant et accessible à tous.');
INSERT INTO places VALUES ('poi-002', 'Le Mazette', 'le-mazette', 'club', 'techno-club', 'festif', 48.843317, 2.369319, 12, 'Port de la Rapée', '#ffab60', 'pin', 1, 4, 0, 'https://source.unsplash.com/ZyTOTmqYYQ8', NULL, 0, 0, '€', 8.5, NULL, NULL, 2.5, 12, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","techno-club"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":18,"is_free":false,"pint_price":8.5,"cocktail_price":0,"coffee_price":2.5,"dish_price":12,"menu_items":[]}', '{"hero":"https://source.unsplash.com/ZyTOTmqYYQ8","gallery":[]}', '[]', NULL, '{"insider_tip":"Le lever de soleil sur la Seine vers 6h du mat''","specials":{"cuisine":[],"drinks":[]}}', 'Anciennement Concrete, cette barge amarrée port de la Rapée a troqué la techno hardcore pour une ambiance solaire et guinguette. Sur trois niveaux dont un immense rooftop végétalisé avec vue imprenable sur la Seine, Le Mazette est devenu le QG des étés parisiens. On y vient pour grignoter des tapas, boire du rosé et danser sous les lampions dès que le soleil se couche. Un lieu hybride qui respire la convivialité et la fête décomplexée.', 'Le lever de soleil sur la Seine vers 6h du mat''', 'Gare de Lyon', '[1,14]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-002', 'Le Mazette', 'club', 'techno-club', 'Port de la Rapée', '', 'Anciennement Concrete, cette barge amarrée port de la Rapée a troqué la techno hardcore pour une ambiance solaire et guinguette. Sur trois niveaux dont un immense rooftop végétalisé avec vue imprenable sur la Seine, Le Mazette est devenu le QG des étés parisiens. On y vient pour grignoter des tapas, boire du rosé et danser sous les lampions dès que le soleil se couche. Un lieu hybride qui respire la convivialité et la fête décomplexée.');
INSERT INTO places VALUES ('poi-032', 'Bois de Vincennes - Lac Daumesnil', 'lac-daumesnil', 'parc', 'lac', 'chill', 48.832175, 2.41577, 12, 'Route de la Ceinture du Lac Daumesnil', '#8ccaf7', 'pin', 1, 4.5, 0, '/images/lac-daumesnil.jpg', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":24.8,"festif":3,"culturel":6.5}', '{}', '["parc","lac"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/lac-daumesnil.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'L''évasion totale à l''Est de Paris. Le Lac Daumesnil, avec ses deux îles (l''île de Reuilly et l''île de Bercy) reliées par un pont suspendu et une rotonde romantique (le temple de l''Amour), est un décor de carte postale 1900. Louer une barque blanche pour ramer au milieu des cygnes et des saules pleureurs est le cliché parisien qu''on adore vivre. C''est bucolique, apaisant et intemporel.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Porte Dorée', '[8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-032', 'Bois de Vincennes - Lac Daumesnil', 'parc', 'lac', 'Route de la Ceinture du Lac Daumesnil', '', 'L''évasion totale à l''Est de Paris. Le Lac Daumesnil, avec ses deux îles (l''île de Reuilly et l''île de Bercy) reliées par un pont suspendu et une rotonde romantique (le temple de l''Amour), est un décor de carte postale 1900. Louer une barque blanche pour ramer au milieu des cygnes et des saules pleureurs est le cliché parisien qu''on adore vivre. C''est bucolique, apaisant et intemporel.');
INSERT INTO places VALUES ('poi-157', 'Batofar', 'batofar', 'club', 'peniche-club', 'festif', 48.833321, 2.37905, 13, '3 Port de la Gare', '#ffab60', 'pin', 1, 4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2bSPGSTOKvXcLSdjjGJvoX3t0f9SKUL1uYX1RyZ1EDmlrVDYMJjoCCekgppttDA_L97EN_4uAd1MmsAhUo3zHYusD9JNgWzKUfk2inWRzi9YhvXvPd28OgBBG5hWzu-1TXmMJCyRtNGk0Si5956oNtOBuRHTl8EoJmE3QWJZ-jNirCaHM6HqTJ7LV9UNg4DQB9VJRv7ZgW-1wa9Q2KojsvKZsuExiSJDklTLug4WNpOI-xYCrXb8KU18S266TqjfN5II5icP0E0KXvf6eL1WjTby9vnr1tX8OmdWhs_ZiO8w&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","peniche-club"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":12,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2bSPGSTOKvXcLSdjjGJvoX3t0f9SKUL1uYX1RyZ1EDmlrVDYMJjoCCekgppttDA_L97EN_4uAd1MmsAhUo3zHYusD9JNgWzKUfk2inWRzi9YhvXvPd28OgBBG5hWzu-1TXmMJCyRtNGk0Si5956oNtOBuRHTl8EoJmE3QWJZ-jNirCaHM6HqTJ7LV9UNg4DQB9VJRv7ZgW-1wa9Q2KojsvKZsuExiSJDklTLug4WNpOI-xYCrXb8KU18S266TqjfN5II5icP0E0KXvf6eL1WjTby9vnr1tX8OmdWhs_ZiO8w&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.","specials":{"cuisine":[],"drinks":[]}}', 'Le Batofar n''est pas qu''un bateau, c''est une légende de la nuit parisienne. Amarré sur les quais de la Seine, ce phare rouge accueille les meilleurs DJs de la scène électro et techno dans sa cale transformée en dancefloor vibrant. La terrasse sur le pont offre une pause magique avec vue sur le fleuve et les tours de la BNF. Une expérience clubbing hors du temps et des conventions, bercée par les flots et les infra-basses.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
