INSERT INTO places VALUES ('poi-169', 'Djoon', 'djoon', 'club', 'club-house', 'festif', 48.836567, 2.371439, 13, '22 Bd Vincent Auriol', '#ffab60', 'pin', 1, 3.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN05r-6JTJkai2OuvSfTr6v6ISTVgkAQNztikSc-yuSytjOo7ESH9ogyRfd49Ie1iXEqI1Oe8CkHca2fr1FMYuHGUFqoIrPWV01eUHLiuuxZsIn01hUqh_gN84Ghw_ezAyafRGASjoENL9WIlGbwZjbS2CbqVGP1PKXku0b7jJkM_3vKwsf9PwOcfTuny1TpG9I_Wd_K327eiVhPPGXDgE0Iy5lnovzLamtTCu11P_-CbELwhZWdptqpK-d_RRtbT5OT6NlPnOKPCxNjJnW65M9HrCp9c6pXjhbHhro3rf9ftA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","club-house"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN05r-6JTJkai2OuvSfTr6v6ISTVgkAQNztikSc-yuSytjOo7ESH9ogyRfd49Ie1iXEqI1Oe8CkHca2fr1FMYuHGUFqoIrPWV01eUHLiuuxZsIn01hUqh_gN84Ghw_ezAyafRGASjoENL9WIlGbwZjbS2CbqVGP1PKXku0b7jJkM_3vKwsf9PwOcfTuny1TpG9I_Wd_K327eiVhPPGXDgE0Iy5lnovzLamtTCu11P_-CbELwhZWdptqpK-d_RRtbT5OT6NlPnOKPCxNjJnW65M9HrCp9c6pXjhbHhro3rf9ftA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.","specials":{"cuisine":[],"drinks":[]}}', 'Le Djoon est le sanctuaire parisien de la house soulful et du disco. Sur deux niveaux dominant les quais de Seine, ce club à l''esprit new-yorkais attire les meilleurs danseurs de la capitale. Programmation afro-house, funky soul et sets pointus des résidents font vibrer le parquet sous les pieds d''un public connaisseur et ultra-bienveillant. Ici, on ne vient pas pour se montrer, mais pour se perdre dans le son et la danse jusqu au petit matin.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-169', 'Djoon', 'club', 'club-house', '22 Bd Vincent Auriol', '', 'Le Djoon est le sanctuaire parisien de la house soulful et du disco. Sur deux niveaux dominant les quais de Seine, ce club à l''esprit new-yorkais attire les meilleurs danseurs de la capitale. Programmation afro-house, funky soul et sets pointus des résidents font vibrer le parquet sous les pieds d''un public connaisseur et ultra-bienveillant. Ici, on ne vient pas pour se montrer, mais pour se perdre dans le son et la danse jusqu au petit matin.');
