JyxrwEwSMzxg9ipYiHHTzn3qYT2neiOGFtIxMBg83miWPW9l1JniWbxrm97Ce746BhUJlZDYg0TtHdKOSKKhNuH6akCT20cz2LbwhR3wqV8IIiXQ2EnhOu12M9hRW3ci_0Aq-XWExQYgzjVYypup15T9AhoAcgzHp9LvrF0C2Af_GNr9VZRxsh01muHdP6OGyYa8cQbgYEK1ITSaW30iVx76R_wIBwcXqdVQWCCdbcvbBaqoobMv9fVjWvNL3Q4yTXJTlovyKzh1DzqG&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Ne manquez pas le Kebbé Nayé (agneau cru au blé concassé) pour les amateurs de sensations fortes, c''est l''un des plus frais de la capitale. La terrasse ensoleillée sur la place est un vrai bonheur au printemps.","specials":{"cuisine":["Traditionnelle Libanaise","Grillades au feu de bois","Mezzés maison"],"drinks":["Arak traditionnel","Vin libanais (Château Musar)"],"must_eat":"Le Plat Baladna et le Houmous maison.","must_drink":"Un verre d''Arak pour ouvrir l''appétit."},"expert_catchline":"La quintessence du Liban à Denfert : mezzés d''une finesse rare et grillades parfumées."}', 'Surplombant la place Denfert-Rochereau, Baladna est une escale libanaise authentique qui refuse les compromis sur la qualité. Ici, les mezzés sont faits maison tous les matins et les grillades au feu de bois embaument la salle. L''ambiance est familiale, généreuse et invite au voyage culinaire entre Beyrouth et Paris. Une valeur sûre pour découvrir la finesse d''un vrai houmous et la tendreté des viandes marinées.', 'Ne manquez pas le Kebbé Nayé (agneau cru au blé concassé) pour les amateurs de sensations fortes, c''est l''un des plus frais de la capitale. La terrasse ensoleillée sur la place est un vrai bonheur au printemps.', 'Denfert-Rochereau', '[4,6]', '[]', 'ChIJX7BUf7dx5kcRHJYpFjxx-6M');
INSERT INTO places_fts VALUES ('poi-baladna', 'Baladna', 'restaurant', 'libanais méditerranéen grillades mezzés restaurant', '26 Pl. Denfert-Rochereau, 75014 Paris', '', 'Surplombant la place Denfert-Rochereau, Baladna est une escale libanaise authentique qui refuse les compromis sur la qualité. Ici, les mezzés sont faits maison tous les matins et les grillades au feu de bois embaument la salle. L''ambiance est familiale, généreuse et invite au voyage culinaire entre Beyrouth et Paris. Une valeur sûre pour découvrir la finesse d''un vrai houmous et la tendreté des viandes marinées.');
