INSERT INTO places_fts VALUES ('poi-augustin', 'Augustin', 'restaurant', 'bistronomique français moderne produits de saison restaurant', '79 Rue Daguerre, 75014 Paris', '', 'Augustin est le joyau chic du quartier Daguerre. Sous la houlette du chef Vincent Deyres, ce bistrot réinvente les codes de la gastronomie française avec une modernité rafraîchissante. Le décor est feutré, l''accueil soigné, et chaque assiette est un tableau où le produit noble est roi. C''est l''adresse idéale pour un dîner intimiste ou un déjeuner d''affaires au calme, loin du tumulte des grandes brasseries montparnassiennes.');
