INSERT INTO places_fts VALUES ('poi-cornichon-75014', 'Le Cornichon', 'restaurant', 'bistronomie moderne marche terrasse gastronomique', '34 Rue Gassendi, 75014 Paris, France', '', 'Le Cornichon est la table bistronomique de référence de la rue Gassendi. Sous ses airs de bistrot de quartier décontracté, il cache une cuisine d''une redoutable précision. Le chef y travaille des produits bruts avec une inventivité qui surprend sans jamais dérouter. L''accueil y est chaleureux et la sélection de vins est pensée pour sublimer chaque assiette. C''est l''endroit parfait pour un déjeuner d''affaires décontracté ou un dîner entre passionnés de gastronomie moderne et accessible.');
