rence=ATCDNfVi-PHFPElBtTMb3uOoKE3MqAwNT-DRCehPUguajpKe0WE5n4Vgw_kMJlTZZqu0lEjDLMqz3rcr1sE-l9XVtrfiGUoQae4A9nFXG4T9NBYUc5HfcB3T4h_Z7bgeNjICjfJJjk5dMFti4dG9gMQDT3T-XF1gjLuIoges3wckMqIdlyuW52-sHoRsFW_ULf1m-hcU85ce-N1rF0AyK0wUrSvAJZI2y8fk16plGGTRyiQN9ea6TItOXeFo5SxIYC-5osdo8P5kxdsOjNXQrugaY19F78-esZC5TWnYgwmUKPHSag&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Ne manquez pas l''os à moelle, un classique parfaitement exécuté. Le menu carte blanche du chef est l''option idéale pour découvrir toute l''étendue de sa créativité. L''ambiance y est très chaleureuse en soirée.","specials":{"cuisine":["Bistronomie","Cuisine d''Auteur"],"drinks":["Sélection de Vignerons","Cocktails de Saison"],"must_eat":"Le Paleron de Boeuf braisé.","must_drink":"Un vin rouge puissant pour accompagner les plats mijotés."},"expert_catchline":"La haute bistronomie de quartier, héritière de la Régalade."}', 'Les Petits Parisiens est le digne successeur de l''esprit Régalade sur l''avenue Jean Moulin. Repris avec brio, ce bistrot chic propose une cuisine d''auteur signée Arnaud Baptiste, qui allie avec maestria les codes de la grande cuisine bourgeoise et une modernité décomplexée. Le cadre est élégant, avec ses banquettes de velours et son éclairage tamisé, créant un cocon idéal pour savourer des assiettes d''une grande justesse. C''est le nouveau repaire des gourmets du sud parisien en quête de sincérité culinaire.', 'Ne manquez pas l''os à moelle, un classique parfaitement exécuté. Le menu carte blanche du chef est l''option idéale pour découvrir toute l''étendue de sa créativité. L''ambiance y est très chaleureuse en soirée.', 'Alésia', '["4"]', '[]', 'ChIJ65kTdVNx5kcRb34kg2awxac');
INSERT INTO places_fts VALUES ('poi-petits-parisiens-75014', 'Les Petits Parisiens', 'restaurant', 'bistronomie moderne terroir institution cosy', '33 Avenue Jean Moulin, 75014 Paris, France', '', 'Les Petits Parisiens est le digne successeur de l''esprit Régalade sur l''avenue Jean Moulin. Repris avec brio, ce bistrot chic propose une cuisine d''auteur signée Arnaud Baptiste, qui allie avec maestria les codes de la grande cuisine bourgeoise et une modernité décomplexée. Le cadre est élégant, avec ses banquettes de velours et son éclairage tamisé, créant un cocon idéal pour savourer des assiettes d''une grande justesse. C''est le nouveau repaire des gourmets du sud parisien en quête de sincérité culinaire.');
