NgwcWr9sXYS_9tOlJhq9uvAkPqDZYgtd58CnNjUaBJrX39OcMF6Ti750x4TE7czNtZDoBNeijgCInwhWeakfm_09D0iKw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le jardin est l''un des plus beaux secrets cachés du quartier, idéal pour les journées ensoleillées. Ne manquez pas les concerts de jazz réguliers qui complètent parfaitement le dîner. L''atmosphère y est incroyablement apaisante.","specials":{"cuisine":["Bistrot de Saison","Options Healthy"],"drinks":["Cocktails Maison","Limonades Artisanales"],"must_eat":"Le Burger Entrepôt et les salades géantes.","must_drink":"Un thé glacé maison dans le jardin."},"expert_catchline":"L''oasis culturelle et gourmande au coeur du 14ème."}', 'L''Entrepôt est un lieu de vie hybride absolument unique dans le 14ème, mêlant cinéma d''art et d''essai, galerie d''art, salle de concert et restaurant. Son plus grand secret est sa magnifique verrière qui s''ouvre sur un jardin intérieur luxuriant, offrant une oasis de calme en plein Paris. La cuisine y est fraîche, de saison et sans prétention, privilégiant les saveurs franches et les assiettes colorées. C''est l''endroit idéal pour un brunch dominical, un verre entre amis après un film ou une pause lecture dans un cadre magique.', 'Le jardin est l''un des plus beaux secrets cachés du quartier, idéal pour les journées ensoleillées. Ne manquez pas les concerts de jazz réguliers qui complètent parfaitement le dîner. L''atmosphère y est incroyablement apaisante.', 'Pernety', '["13"]', '[]', 'ChIJbWYjnaBx5kcR2GLcrOR_LgY');
INSERT INTO places_fts VALUES ('poi-entrepot-75014', 'L''Entrepôt', 'restaurant', 'jardin culturel bistrot cinema insolite', '7 Rue Francis de Pressensé, 75014 Paris, France', '', 'L''Entrepôt est un lieu de vie hybride absolument unique dans le 14ème, mêlant cinéma d''art et d''essai, galerie d''art, salle de concert et restaurant. Son plus grand secret est sa magnifique verrière qui s''ouvre sur un jardin intérieur luxuriant, offrant une oasis de calme en plein Paris. La cuisine y est fraîche, de saison et sans prétention, privilégiant les saveurs franches et les assiettes colorées. C''est l''endroit idéal pour un brunch dominical, un verre entre amis après un film ou une pause lecture dans un cadre magique.');
