?maxwidth=1600&photo_reference=ATCDNfXTZIGnVgbRUvDJKdlOu4JIJW-LWOcwmePucXA0cZCAUor0OdsmvWYmmNujqCNI9IwUN3dYfs7B6k4czE0zVg7idAdF5dORWv9s2IKcphoS0KIfDsUZnGTFaxk-F1zKl0f75UJIBeE2qKMBCc5HVkoTj-cV6aYTxFDALO2Rh1VRwMLhWGcrPgkCWb_gAQBYmD7KiWeb2Gcpv1UWGW6yI0MAp_f1xaSj6JslNzUSWouAK8FwXOpylLtERla30_cq_gf3k2AbsU_2cX5O6Eot4BcOS8XSglh305vJuNZ26FEpJQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Les concerts débutent généralement à 21h, mais arrivez dès 18h30 pour l''apéritif dans la véranda, l''ambiance y est déjà magique. Pensez à réserver les tables en bord de scène pour une immersion totale.","specials":{"cuisine":["Bistronomie Française","Planches à Partager"],"drinks":["Vins de Propriété","Cocktails Classiques"],"must_eat":"L''Entrecôte sauce Béarnaise et le Pavé Chocolat Guanaja.","must_drink":"Un verre de vin rouge corsé pendant le deuxième set."},"expert_catchline":"Gastronomie de bistrot et sets de jazz magistraux à Montparnasse."}', 'Le temple de la note bleue à Montparnasse. Le Jazz Café Montparnasse perpétue l''esprit légendaire des jazz clubs parisiens dans un cadre moderne, confortable et acoustiquement irréprochable. Ici, la musique ne se savoure pas seulement avec les oreilles, mais aussi avec une cuisine de bistrot généreuse et soignée. La scène accueille chaque soir des pointures internationales et des talents émergents, créant une atmosphère électrique où les verres s''entrechoquent au rythme du swing. C''est le lieu parfait pour une soirée hors du temps, entre improvisation culinaire et virtuosité musicale.', 'Les concerts débutent généralement à 21h, mais arrivez dès 18h30 pour l''apéritif dans la véranda, l''ambiance y est déjà magique. Pensez à réserver les tables en bord de scène pour une immersion totale.', 'Gaîté', '["13"]', '[]', 'ChIJVVVVzspx5kcR-5LwER4FSEE');
INSERT INTO places_fts VALUES ('poi-jazz-cafe-montparnasse', 'Jazz Café Montparnasse', 'restaurant', 'jazz concert bistrot musique culturel nocturne', '13 Rue du Commandant René Mouchotte, 75014 Paris, France', '', 'Le temple de la note bleue à Montparnasse. Le Jazz Café Montparnasse perpétue l''esprit légendaire des jazz clubs parisiens dans un cadre moderne, confortable et acoustiquement irréprochable. Ici, la musique ne se savoure pas seulement avec les oreilles, mais aussi avec une cuisine de bistrot généreuse et soignée. La scène accueille chaque soir des pointures internationales et des talents émergents, créant une atmosphère électrique où les verres s''entrechoquent au rythme du swing. C''est le lieu parfait pour une soirée hors du temps, entre improvisation culinaire et virtuosité musicale.');
