-1J04TIbchD_8jew31SLGu3--babB09H5tKsdHD10BewZKcowsoV4-jhpFcvxDscObbrsnZJRVL34MC3q6EkWw_VT3UdwhsZMuanRnPbQmXupZt-0brxjp4YuSdM7YIvlTMLoncitql3j8FzQSibF3mBdQf8pk_RFdmDeGw0csvbFiMrb5p85NsBTjjIotBQYuqs8ZY&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Leur Happy Hour est l''un des plus généreux du quartier, incluant des cocktails créatifs et des planches de produits sourcés. C''est aussi l''endroit parfait pour observer le tumulte parisien depuis la terrasse sans être pressé par le service.","specials":{"cuisine":["Bistrot Français","Tapas"],"drinks":["Large choix de Bières","Cocktails Happy Hour"],"must_eat":"L''Hamburger maison au Cantal et les Oeufs Cocotte.","must_drink":"Une bière pression rafraîchissante en terrasse."},"expert_catchline":"L''escale vibrante et conviviale face à Denfert-Rochereau."}', 'Posté à l''angle stratégique de la place Denfert-Rochereau, le Café du Rendez-Vous est le point de ralliement incontournable du quartier. Ce grand bistrot parisien, avec sa terrasse chauffée qui s''étire généreusement sur le trottoir, offre une animation constante du petit-déjeuner au dernier verre nocturne. L''ambiance y est cosmopolite, vibrante et décontractée, attirant aussi bien les voyageurs en transit que les habitués du 14ème. C''est le lieu idéal pour une pause rapide, un déjeuner de travail efficace ou un Happy Hour prolongé entre amis, le tout dans un décor de brasserie moderne et chaleureuse.', 'Leur Happy Hour est l''un des plus généreux du quartier, incluant des cocktails créatifs et des planches de produits sourcés. C''est aussi l''endroit parfait pour observer le tumulte parisien depuis la terrasse sans être pressé par le service.', 'Denfert-Rochereau', '["4","6","RER B"]', '[]', 'ChIJEYElfrdx5kcR8NJ6jn7CDG8');
INSERT INTO places_fts VALUES ('poi-cafe-du-rendez-vous', 'Café du Rendez-Vous', 'café', 'bistrot terrasse brasserie denfert-rochereau parisien cocktails', '2 Avenue du Général Leclerc, 75014 Paris, France', '', 'Posté à l''angle stratégique de la place Denfert-Rochereau, le Café du Rendez-Vous est le point de ralliement incontournable du quartier. Ce grand bistrot parisien, avec sa terrasse chauffée qui s''étire généreusement sur le trottoir, offre une animation constante du petit-déjeuner au dernier verre nocturne. L''ambiance y est cosmopolite, vibrante et décontractée, attirant aussi bien les voyageurs en transit que les habitués du 14ème. C''est le lieu idéal pour une pause rapide, un déjeuner de travail efficace ou un Happy Hour prolongé entre amis, le tout dans un décor de brasserie moderne et chaleureuse.');
