INSERT INTO places_fts VALUES ('poi-imprevu-alesia', 'L''Imprévu', 'restaurant', 'bistrot terrasse brasserie quartier moderne nocturne', '13 Rue d''Alésia, 75014 Paris, France', '', 'L''Imprévu est le caméléon gourmand de la rue d''Alésia. Que ce soit pour un brunch tardif, un déjeuner aux accents asiatiques ou une soirée tapas-cocktails sur sa terrasse toujours animée, l''établissement s''adapte à tous les moments de la vie parisienne. Son décor moderne, son accueil chaleureux et sa carte éclectique en font un lieu de passage privilégié pour ceux qui aiment la diversité. C''est l''endroit où l''on s''arrête par hasard et d''où l''on repart avec l''envie de revenir, séduit par la justesse des saveurs et la décontraction du service.');
