maxwidth=1600&photo_reference=ATCDNfU3bhHEvh387FEgwmdnQiLypByPjroJZTydAkuOk1EBlSK8e7zr7SastA_ZJc6QiWjpZaIZJuARhVjuUfuiooTsST9dKK1UTDzsgM8jpAOIvlwStTgLXkwwztWwLy5zio-G7_XCKlKqCFH3c-I9ILDTb23E9mjqUI85WB-FBWKGMgn6q7pgStJxOoi1XNjDcqo6bsngWETY1m2cOC_O0oT-P571zNx7eHjHAMzvd3dtmvIJwVU4TKWA7-4agqdgwXR-bmW6NIlwONgPyzJTx5xo4M5IjrvxBXj4Eqy2m9NHpu3SIt4ffztwru9vbDOlANhKefeW-AuJFs7Av5xe-8IaRx-FhUXtR2NpDf-ttTga1XcjJK3Co5OZnmPyzcsJFFgZVZREFk0y0xM4FlLnlxJ25zL5t7TBU1_6O21Jqwx-49L8mIAujf_ZrRrVaA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Demandez une table en terrasse si le temps le permet, l''impasse est très charmante. La pizza Tripletta avec sa N''duja (saucisse piquante calabraise) est un must pour les amateurs de sensations fortes.","specials":{"cuisine":["Napolitaine","Italienne Contemporaine"],"drinks":["Spritz","Vins Italiens Bio","Bières Artisanales"],"must_eat":"La pizza Tripletta et la Burrata Pugliese.","must_drink":"Un Spritz classique ou un vin rouge des Pouilles."},"expert_catchline":"La pizza napolitaine pure et vibrante à Montparnasse."}', 'Tripletta Gaité est l''ambassade de la pizza napolitaine dans le quartier de la Gaité. Avec son four à bois imposant et sa décoration industrielle chaleureuse, le lieu dégage une énergie vibrante dès l''entrée. La pâte, longuement maturée, est une merveille de légèreté et de moelleux, garnie de produits sourcés directement en Italie. La terrasse, située dans une petite impasse calme, est une pépite rare dans ce quartier animé. C''est l''adresse idéale pour une pizza entre amis avant une séance de théâtre.', 'Demandez une table en terrasse si le temps le permet, l''impasse est très charmante. La pizza Tripletta avec sa N''duja (saucisse piquante calabraise) est un must pour les amateurs de sensations fortes.', 'Gaité', '["13"]', '[]', 'ChIJlaEwLn9x5kcRLsh7q_LCDkM');
INSERT INTO places_fts VALUES ('poi-tripletta-gaite-75014', 'Tripletta Gaité', 'restaurant', 'pizza italien vibrant terrasse napolitain', '1 Impasse de la Gaité, 75014 Paris, France', '', 'Tripletta Gaité est l''ambassade de la pizza napolitaine dans le quartier de la Gaité. Avec son four à bois imposant et sa décoration industrielle chaleureuse, le lieu dégage une énergie vibrante dès l''entrée. La pâte, longuement maturée, est une merveille de légèreté et de moelleux, garnie de produits sourcés directement en Italie. La terrasse, située dans une petite impasse calme, est une pépite rare dans ce quartier animé. C''est l''adresse idéale pour une pizza entre amis avant une séance de théâtre.');
