maxwidth=1600&photo_reference=ATCDNfUfbh9dZA9jtr8hTl_BImlCHIjl7vAZ18DQPCou6neozS25lN91rMQKY1dWP9Boek5SOoHTecUnCDIFs2Lpe8EzuegobPwldYsh00u3liBwXUnk_yKRPL3BkRJodS41S3k5eUNPNTJAGpxVOxWHioRWQ92D-5zJrB6-k5QhUvKP1qDZxryqQ_MWemwoFbZgPZGcJ3zZ_aAXj2OBaUOkKywNV8B46qzp15TmRbxY7aexhOJCTVQRufGY62n044nTccKkhShl6lhz10vwuZz6coshe1kzr535q2pM8HeWMCDsRA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Ne faites pas l''impasse sur l''andouillette si vous êtes amateur, elle est certifiée AAAAA et parfaitement grillée. Le plateau de fromages est une sélection tournante de petits producteurs de nos régions.","specials":{"cuisine":["Terroir Français","Cuisine Grand-Mère"],"drinks":["Pichets de Vin de Pays","Liqueurs Digestives"],"must_eat":"L''Andouillette AAAAA et le Confit de Canard.","must_drink":"Un rouge charpenté du Sud-Ouest."},"expert_catchline":"Tout le charme et la saveur des campagnes françaises dans votre assiette."}', 'Le Bistrot des Campagnes est une véritable invitation au voyage dans la France rurale au coeur du Paris moderne. Avec ses boiseries sombres, ses nappes à carreaux et ses affiches vintage, le décor plante le décor d''une gastronomie généreuse et sans complexe. On y vient pour retrouver les saveurs perdues de l''enfance : des mijotés longuement préparés, des produits de terroir sourcés avec soin et une ambiance conviviale inimitable. La petite terrasse est un havre de paix idéal pour savourer un bon verre de vin de pays.', 'Ne faites pas l''impasse sur l''andouillette si vous êtes amateur, elle est certifiée AAAAA et parfaitement grillée. Le plateau de fromages est une sélection tournante de petits producteurs de nos régions.', 'Raspail', '["4","6"]', '[]', 'ChIJodz_tshx5kcRUayAaJCnP2A');
INSERT INTO places_fts VALUES ('poi-bistrot-campagnes-75014', 'Le Bistrot des Campagnes', 'restaurant', 'traditionnel terroir terrasse rustique chaleureux', '6 Rue Léopold Robert, 75014 Paris, France', '', 'Le Bistrot des Campagnes est une véritable invitation au voyage dans la France rurale au coeur du Paris moderne. Avec ses boiseries sombres, ses nappes à carreaux et ses affiches vintage, le décor plante le décor d''une gastronomie généreuse et sans complexe. On y vient pour retrouver les saveurs perdues de l''enfance : des mijotés longuement préparés, des produits de terroir sourcés avec soin et une ambiance conviviale inimitable. La petite terrasse est un havre de paix idéal pour savourer un bon verre de vin de pays.');
