INSERT INTO places VALUES ('poi-206', 'Dose Batignolles', 'dose-batignolles', 'café', 'specialty-coffee', 'chill', 48.88709, 2.317899, 17, '82 Place du Dr Félix Lobligeois', '#8ccaf7', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN34jHK8_P_H22FdoEAjddqDfZLDhKbKYJomic7e4-Iem6y42LpzMcEuM5Vbm8ujYwXnJNakwyCOlrMCQIT5YnvSDcEFXCdOaEFfHM3JprZgd16JkD-w13b7OiW5bzXQtWTdnnUzAwXp-3vqGDRBW-0LDyUsFUKNWtcrCbf8qfH9WkXZyxtySCZkBudi2aORu2a4G6RmP8YfY3RU4v7YVmtsDlRANpcjw6aJeVtml_jg022BrhEs7GKFdvuv5teemR-CieOfZpDoLJ3wrOnKCj5p0Htn2KFrUwKoLOoLKmjCWQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","specialty-coffee"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN34jHK8_P_H22FdoEAjddqDfZLDhKbKYJomic7e4-Iem6y42LpzMcEuM5Vbm8ujYwXnJNakwyCOlrMCQIT5YnvSDcEFXCdOaEFfHM3JprZgd16JkD-w13b7OiW5bzXQtWTdnnUzAwXp-3vqGDRBW-0LDyUsFUKNWtcrCbf8qfH9WkXZyxtySCZkBudi2aORu2a4G6RmP8YfY3RU4v7YVmtsDlRANpcjw6aJeVtml_jg022BrhEs7GKFdvuv5teemR-CieOfZpDoLJ3wrOnKCj5p0Htn2KFrUwKoLOoLKmjCWQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Dose est bien plus qu''un simple café, c''est l''antre des puristes du grain aux Batignolles. Installé face au parc, ce coffee shop propose une torréfaction propre et une expertise rare sur chaque tasse. Du V60 au Flat White, chaque extraction est une leçon de goût. L''ambiance y est cool et studieuse, complétée par une offre de brunch gourmande et des jus frais pressés minute. C''est l''essence même du ''third wave coffee'' appliqué avec passion dans un cadre de quartier chaleureux.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL);
