y=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Art Brut et café librairie atypique au pied de Montmartre.","specials":{"cuisine":[],"drinks":[]}}', 'Au pied du Sacré-Cœur, dans une ancienne halle de marché style Baltard, se trouve ce musée dédié à l''art brut et à l''art singulier. C''est le musée des artistes marginaux, des fous et des visionnaires. L''ambiance y est unique, loin des musées classiques aseptisés. Le café sous la verrière, entouré de livres d''art et de gâteaux maison, est un lieu de détente génial après avoir grimpé les marches de Montmartre.', 'Art Brut et café librairie atypique au pied de Montmartre.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-062', 'Halle Saint-Pierre', 'museum', 'espace-culturel', '2 Rue Ronsard', '', 'Au pied du Sacré-Cœur, dans une ancienne halle de marché style Baltard, se trouve ce musée dédié à l''art brut et à l''art singulier. C''est le musée des artistes marginaux, des fous et des visionnaires. L''ambiance y est unique, loin des musées classiques aseptisés. Le café sous la verrière, entouré de livres d''art et de gâteaux maison, est un lieu de détente génial après avoir grimpé les marches de Montmartre.');
INSERT INTO places VALUES ('poi-079', 'La Station — Gare des Mines', 'la-station', 'club', 'friche-culturelle', 'festif', 48.901224, 2.369937, 18, '29 Av. de la Prte d''Aubervilliers', '#ffab60', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0a35TXiMUVntUrWpiWx2pjdOPR3FBdmqtdvczlSK4KRdIk6SUAISmrLB3LI8pEOgdCvkF3p7SVPfSXP2tyY0a6avQXhUZPo-U_vlKASKqTWpNo5V0li4RO4SWIuE13-_hJPivEAjB4awQ442FdwjL9vd4eMTPJWYOuJ3QpB0Mb_jCVQNIO6lBRytv1Y1LmgIYR3j5hE-5Ia1pGNqUIJ78krCPobZUnp1T-asaRoDnYRRgSPnRM-1siVMYHQ6pyzL7QBxBwl-o-Z7YajsQYR6ZnLDn5r-UFKcFdDtnCtgeenQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', 6, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","friche-culturelle"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":6,"is_free":false,"pint_price":6,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0a35TXiMUVntUrWpiWx2pjdOPR3FBdmqtdvczlSK4KRdIk6SUAISmrLB3LI8pEOgdCvkF3p7SVPfSXP2tyY0a6avQXhUZPo-U_vlKASKqTWpNo5V0li4RO4SWIuE13-_hJPivEAjB4awQ442FdwjL9vd4eMTPJWYOuJ3QpB0Mb_jCVQNIO6lBRytv1Y1LmgIYR3j5hE-5Ia1pGNqUIJ78krCPobZUnp1T-asaRoDnYRRgSPnRM-1siVMYHQ6pyzL7QBxBwl-o-Z7YajsQYR6ZnLDn5r-UFKcFdDtnCtgeenQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.","specials":{"cuisine":[],"drinks":[]}}', 'Née dans une ancienne gare de charbons à la lisière d''Aubervilliers, La Station est le projet fou du collectif MU. C''est une friche culturelle à l''état pur, où l''esthétique industrielle et bétonnée sert de décor à l''avant-garde musicale et artistique. Pendant les mois d''été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C''est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l''imprévu, le son fort, et cette vibration brute qu''on ne trouve plus nulle part ailleurs.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-079', 'La Station — Gare des Mines', 'club', 'friche-culturelle', '29 Av. de la Prte d''Aubervilliers', '', 'Née dans une ancienne gare de charbons à la lisière d''Aubervilliers, La Station est le projet fou du collectif MU. C''est une friche culturelle à l''état pur, où l''esthétique industrielle et bétonnée sert de décor à l''avant-garde musicale et artistique. Pendant les mois d''été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C''est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l''imprévu, le son fort, et cette vibration brute qu''on ne trouve plus nulle part ailleurs.');
INSERT INTO places VALUES ('poi-123', 'Musée de Montmartre', 'musee-de-montmartre', 'museum', 'musée / vignobles', 'culturel', 48.887709, 2.340673, 18, '12 Rue Cortot', '#c499ff', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3tyjT4JgL1blQa2E82DeKopfJxVM7HE-_VIYcEj34tbEtNWDzv-if6i4-hxg8Wi7jfOq7bAjricJCRRzg-f6H-NnZa3fS1VK0vhctE5mjHyFFU_9hgnSHNH6E7Wl8sTxyAiwXmpqzK1cY_rqAfZCXnMns4UhUNzrVFKlKgT5oGsWiVnQrnJoAwE2lgtsYcz825Ji_j-WVUAVZaUUMtOm1KdeXEIOuw65GiAVRf9s1MXPwKqYri9_PPWPSsWFdggUFq3ckAz-Y85o7XvMQXm56cWRIrOD6iRb7-uLo3qzCgBsETFk1QrVkTGl3XhzDMshbdnquovg3yfaSkNqeBD09cRaZodOWTfrkE6i1hAfJBvnnSxrBiMyVrsStSZVKNvFNMXSD5k4oyn5yHCC3QB9m7jIyTDKLqGENyjg4zDaUivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":9.2,"festif":4,"culturel":25}', '{}', '["museum","musée / vignobles"]', '{"standard":"","display":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":7,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3tyjT4JgL1blQa2E82DeKopfJxVM7HE-_VIYcEj34tbEtNWDzv-if6i4-hxg8Wi7jfOq7bAjricJCRRzg-f6H-NnZa3fS1VK0vhctE5mjHyFFU_9hgnSHNH6E7Wl8sTxyAiwXmpqzK1cY_rqAfZCXnMns4UhUNzrVFKlKgT5oGsWiVnQrnJoAwE2lgtsYcz825Ji_j-WVUAVZaUUMtOm1KdeXEIOuw65GiAVRf9s1MXPwKqYri9_PPWPSsWFdggUFq3ckAz-Y85o7XvMQXm56cWRIrOD6iRb7-uLo3qzCgBsETFk1QrVkTGl3XhzDMshbdnquovg3yfaSkNqeBD09cRaZodOWTfrkE6i1hAfJBvnnSxrBiMyVrsStSZVKNvFNMXSD5k4oyn5yHCC3QB9m7jIyTDKLqGENyjg4zDaUivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Niché dans la plus vieille maison de la colline de Montmartre, ce musée est un enchantement total. Entre ses jardins inspirés des tableaux de Renoir et ses vues plongeantes sur les vignes du Clos Montmartre, le lieu respire l''esprit bohème de la Belle Époque. On y revit les heures de gloire du Bateau-Lavoir et d''Erik Satie dans une atmosphère bucolique et secrète, loin de l''agitation de la Place du Tertre.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-123', 'Musée de Montmartre', 'museum', 'musée / vignobles', '12 Rue Cortot', '', 'Niché dans la plus vieille maison de la colline de Montmartre, ce musée est un enchantement total. Entre ses jardins inspirés des tableaux de Renoir et ses vues plongeantes sur les vignes du Clos Montmartre, le lieu respire l''esprit bohème de la Belle Époque. On y revit les heures de gloire du Bateau-Lavoir et d''Erik Satie dans une atmosphère bucolique et secrète, loin de l''agitation de la Place du Tertre.');
